+        while startIndex < audioBuffer.count {
+            let endIndex = min(startIndex + maxCount, audioBuffer.count)
+            audioChunks.append(Array(audioBuffer[startIndex..<endIndex]))
+            startIndex = endIndex
+        }
+
+        return audioChunks
+    }
